import React, { useState } from "react";

class Project {
  constructor(name, description, mediaLinks) {
    this.name = name;
    this.description = description;
    this.mediaLinks = mediaLinks;
  }
}

function Projects() {
  const [selectedProject, setSelectedProject] = useState(null);

  const projects = [
    new Project(
      'Radiation Detector & Mobile App',
      'A portable radiation detection tool.',
      [
        { type: 'image', src: "../assets/maps_pages.jpg" },
        { type: 'image', src: "../assets/records_page.jpg" },
        { type: 'image', src: "../assets/home_page.jpg" },
        { type: 'image', src: "../assets/map.jpg" },
        { type: 'image', src: "../assets/top_level_design.jpg" }
      ]),
    new Project(
      'WonderTales: Educational Web App for Kids',
      'Inspired by my first born, I wanted to create a website that fosters hands-on learning with parent engagement that is both fun and stimulates critical thinking.',
      [null]
    ),
    new Project(
      'AI-Driven Financial Market Analysis',
      'As my introduction into data science I utilized the power of Pythons Numpy, Pandas, Seaborn, Matplotlib, and Sklearn to clean, normalize, analyze, and visualize Bank Loan data',
      [{ type: 'pdf', src: '../assets/projects/Data_science.pdf' }]
    ),
    new Project(
      'DJ Party App',
      'React Native and Google Maps based music vote app.',
      [{ type: 'video', src: '../assets/projects/DJ_party_app.mp4' }]
    ),
    new Project(
      'DB Management of Business Financial Statements',
      'SQL DB design, views, joins, and aggregation. Visit https://youtu.be/4PeZ3Ih4iPo for a live demonstration.',
      [
        { type: 'image', src: 'db_schema.png' },
        { type: 'image', src: 'db_view.png' },
        { type: 'image', src: 'db_update.png' }
      ]
    ),
    new Project(
      'Baby Habit Tracker',
      'Uses M5 StickC Plus 2 and Firebase to monitor a newborn.',
      [
        { type: 'image', src: "../assets/projects/habit_tracker_1.jpg" },
        { type: 'image', src: "../assets/projects/habit_tracker_2.jpg" },
        { type: 'image', src: "../assets/projects/habit_tracker_3.jpg" },
        { type: 'video', src: "../assets/projects/Baby_habit_tracker.mp4" }
      ]
    ),
    new Project(
      'Budget Tool',
      'A personal budget tool using VBA for Excel.',
      [{ type: 'video', src: "../assets/projects/Budget.mp4" }]
    ),
    new Project(
      'Conquest',
      'My first game, a tabletop-style PC game in Python.',
      [{ type: 'video', src: "../assets/projects/Conquest.mp4" }]
    ),
    new Project(
      'Webscraping Stock Market and Financial Data',
      'Two Python scripts using Pandas, Requests, and BeautifulSoup for pulling and exporting financial data.',
      [] // No media yet
    ),
  ];

  return (
    <div style={styles.container}>
      <div style={styles.list}>
        {projects.map((proj, index) => (
          <div
            key={index}
            style={styles.item}
            onClick={() => setSelectedProject(proj)}
            onMouseEnter={e => (e.currentTarget.style.backgroundColor = styles.itemHover.backgroundColor)}
            onMouseLeave={e => (e.currentTarget.style.backgroundColor = '')}
          >
            {proj.name}
          </div>
        ))}
      </div>

      <div style={styles.display}>
        {selectedProject ? (
          <>
            <h2>{selectedProject.name}</h2>
            <p>{selectedProject.description}</p>
            <div>
              {selectedProject.mediaLinks.length > 0 ? (
                selectedProject.mediaLinks.map((media, idx) => {
                  if (!media || !media.src) return null;

                  switch (media.type) {
                    case 'image':
                      return <img key={idx} src={media.src} alt={`media-${idx}`} style={styles.media} />;
                    case 'video':
                      return (
                        <video key={idx} controls style={styles.media}>
                          <source src={media.src} type="video/mp4" />
                        </video>
                      );
                    case 'pdf':
                    case 'ppt':
                      return (
                        <iframe
                          key={idx}
                          src={media.src}
                          title={`doc-${idx}`}
                          style={styles.iframe}
                        />
                      );
                    default:
                      return <p key={idx}>Unsupported media type: {media.type}</p>;
                  }
                })
              ) : (
                <p><em>No media available for this project.</em></p>
              )}
            </div>
          </>
        ) : (
          <p>Select a project to see its details</p>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    gap: '20px',
    padding: '20px',
  },
  list: {
    width: '30%',
    borderRight: '1px solid #ccc',
  },
  item: {
    cursor: 'pointer',
    padding: '10px',
    borderBottom: '1px solid #eee',
  },
  itemHover: {
    backgroundColor: '#f0f0f0',
  },
  display: {
    flex: 1,
  },
  media: {
    marginTop: '10px',
    maxWidth: '100%',
    borderRadius: '8px',
  },
  iframe: {
    marginTop: '10px',
    width: '100%',
    height: '600px',
    borderRadius: '8px',
    border: 'none',
  }
};

export default Projects;
